sql:
SELECT AVG(rating) AS average_rating
FROM ratings_and_reviews
WHERE book_id = 1;

SELECT COUNT(reservation_id) AS reservation_count
FROM reservations
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'Bob Williams');

SELECT b.title
FROM books b
WHERE b.book_id IN (
    SELECT r.book_id FROM reservations r
)
AND b.book_id IN (
    SELECT bh.book_id FROM borrowing_history bh
)
AND b.book_id IN (
    SELECT rr.book_id FROM ratings_and_reviews rr
);

external_knowledge:
- Popularity score refers to the number of times a book has been borrowed; 
- Average rating is calculated based on user reviews and ratings (1-5); 
- The top 5 books are determined by their borrow count in descending order.
